import { HolisticResults } from '../types';

/**
 * FeatureExtractor - ML Integrity Version
 * 
 * CRITICAL COORDINATE STANDARDS:
 * 1. Inputs: Raw normalized coordinates [0.0 - 1.0] from MediaPipe.
 * 2. Space: Shoulder-Relative (Unit-Shoulder). 1.0 = Shoulder Width.
 * 3. Extraction Order: 33 Pose -> 21 Left Hand -> 21 Right Hand.
 */

export interface ExtractionResult {
  data: number[];
  meta: {
    pose: number;
    lh: number;
    rh: number;
    refX: number;
    refY: number;
    scale: number;
    handImputed: boolean;
  };
}

export class FeatureExtractor {
  static extract(results: any, swapHands: boolean = false): ExtractionResult {
    const frameData: number[] = [];
    let refX = 0, refY = 0, refZ = 0, scaleFactor = 1.0;
    const epsilon = 1e-8;
    let handImputed = false;

    // 1. Reference Calculation (Indices 11 & 12 are shoulders)
    if (results.poseLandmarks && results.poseLandmarks[11] && results.poseLandmarks[12]) {
      const lS = results.poseLandmarks[11];
      const rS = results.poseLandmarks[12];

      refX = (lS.x + rS.x) / 2;
      refY = (lS.y + rS.y) / 2;
      refZ = ((lS.z || 0) + (rS.z || 0)) / 2;

      const shoulderWidth = Math.sqrt(
        Math.pow(lS.x - rS.x, 2) + 
        Math.pow(lS.y - rS.y, 2) + 
        Math.pow((lS.z || 0) - (rS.z || 0), 2)
      );

      scaleFactor = 1.0 / (shoulderWidth + epsilon);
    }

    // 2. Pose Extraction (33 points)
    for (let i = 0; i < 33; i++) {
      const p = (results.poseLandmarks && results.poseLandmarks[i]) 
        ? results.poseLandmarks[i] 
        : { x: 0, y: 0, z: 0 };

      frameData.push(
        (p.x - refX) * scaleFactor, 
        (p.y - refY) * scaleFactor, 
        ((p.z || 0) - refZ) * scaleFactor
      );
    }

    // 3. Hand Extraction (21 points per hand)
    const processHand = (landmarks: any[] | undefined) => {
      const has = !!(landmarks && landmarks.length > 0);
      if (!has) handImputed = true;
      for (let i = 0; i < 21; i++) {
        const p = (has && landmarks![i]) ? landmarks![i] : { x: 0, y: 0, z: 0 };
        frameData.push(
          (p.x - refX) * scaleFactor,
          (p.y - refY) * scaleFactor,
          ((p.z || 0) - refZ) * scaleFactor
        );
      }
    };

    const leftSource = swapHands ? results.rightHandLandmarks : results.leftHandLandmarks;
    const rightSource = swapHands ? results.leftHandLandmarks : results.rightHandLandmarks;

    processHand(leftSource);
    processHand(rightSource);

    return {
      data: frameData,
      meta: {
        pose: results.poseLandmarks?.length || 0,
        lh: leftSource?.length || 0,
        rh: rightSource?.length || 0,
        refX,
        refY,
        scale: 1.0 / scaleFactor,
        handImputed
      }
    };
  }
}

import * as ort from 'onnxruntime-web';
import { PredictionResult, AppConfig } from "../types";

const ORT_VERSION = '1.20.0';
const CDN_URL = `https://cdn.jsdelivr.net/npm/onnxruntime-web@${ORT_VERSION}/dist/`;

ort.env.wasm.wasmPaths = CDN_URL;
ort.env.wasm.numThreads = 1;
ort.env.wasm.simd = false;
ort.env.wasm.proxy = false; 

export interface InferenceDebugInfo {
  min: number;
  max: number;
  mean: number;
  top10: { word: string; confidence: number }[];
  inputShape: number[];
}

export class SignEngine {
  private session: ort.InferenceSession | null = null;
  private isModelLoaded = false;
  private isInitializing = true;
  private initializationError: string | null = null;

  constructor() {
    this.initLocalModel();
  }

  private async initLocalModel() {
    try {
      const response = await fetch('./models/model.onnx');
      if (!response.ok) throw new Error(`Model missing at ./models/model.onnx`);
      const modelBuffer = await response.arrayBuffer();
      this.session = await ort.InferenceSession.create(new Uint8Array(modelBuffer), {
        executionProviders: ['wasm'],
        graphOptimizationLevel: 'all'
      });
      this.isModelLoaded = true;
    } catch (e: any) {
      this.initializationError = e.message || "Init failed";
    } finally {
      this.isInitializing = false;
    }
  }

  private softmax(arr: number[]): number[] {
    const maxLogit = Math.max(...arr);
    const exps = arr.map(x => Math.exp(x - maxLogit));
    const sumExps = exps.reduce((a, b) => a + b, 0);
    return exps.map(x => x / (sumExps || 1));
  }

  async predict(sequence: number[][], config: AppConfig): Promise<{ result: PredictionResult | null; debug: InferenceDebugInfo } | null> {
    if (!this.isModelLoaded || !this.session) return null;

    try {
      const targetFrames = 64; 
      const totalFeatures = 225; // 75 points * 3
      const tensorSize = targetFrames * totalFeatures;
      const flattened = new Float32Array(tensorSize);

      // TEMPORAL CONSISTENCY: Pad with last available frame to avoid zero-shocks
      const lastAvailableFrame = sequence.length > 0 
        ? sequence[sequence.length - 1] 
        : new Array(totalFeatures).fill(0);

      // We either take the latest 64 frames or pad from the end
      const actualSequence = sequence.length > targetFrames 
        ? sequence.slice(sequence.length - targetFrames)
        : sequence;

      for (let i = 0; i < targetFrames; i++) {
        const frameData = actualSequence[i] || lastAvailableFrame;
        flattened.set(frameData.slice(0, totalFeatures), i * totalFeatures);
      }

      const shape = [1, targetFrames, totalFeatures];
      const tensor = new ort.Tensor('float32', flattened, shape);
      const results = await this.session.run({ [this.session.inputNames[0]]: tensor });
      const outputData = Array.from(results[this.session.outputNames[0]].data as Float32Array);
      const probs = this.softmax(outputData);

      const indexedProbs = probs.map((p, i) => ({ 
        word: config.model_config.labels[i] || `L${i}`, 
        confidence: p 
      })).sort((a, b) => b.confidence - a.confidence);

      const debug: InferenceDebugInfo = { 
        min: Math.min(...flattened), 
        max: Math.max(...flattened), 
        mean: flattened.reduce((a, b) => a + b, 0) / flattened.length,
        top10: indexedProbs.slice(0, 10), 
        inputShape: shape 
      };

      const result = indexedProbs[0];
      return { 
        result: result.confidence >= config.inference_logic.confidence_threshold 
          ? result 
          : { word: 'NA', confidence: result.confidence }, 
        debug 
      };
    } catch (err) {
      console.error("Inference Error:", err);
      return null;
    }
  }

  public getEngineStatus() {
    if (this.isInitializing) return 'BOOTING...';
    if (this.initializationError) return 'INIT FAILED';
    return this.isModelLoaded ? 'READY (75-KP)' : 'OFFLINE';
  }
}

export const signEngine = new SignEngine();

import React, { useEffect, useRef, useState } from 'react';
import * as HolisticModule from '@mediapipe/holistic';
import * as CameraModule from '@mediapipe/camera_utils';
import * as DrawingModule from '@mediapipe/drawing_utils';
import { HolisticResults, AppConfig, ViewportStatus, PredictionResult, SessionState } from '../types';
import { FeatureExtractor } from '../services/FeatureExtractor';

interface HolisticCameraProps {
  enabled: boolean;
  config: AppConfig;
  facingMode: 'user' | 'environment';
  isMirrored: boolean;
  prediction: PredictionResult | null;
  isAnalyzing: boolean;
  onViewportStatusChange: (status: ViewportStatus) => void;
  onResults: (results: HolisticResults, filteredPoints: number[]) => void;
  onSequenceComplete: (sequence: number[][]) => void;
  onFpsUpdate: (fps: number) => void;
  onError: (error: string) => void;
}

const HolisticCamera: React.FC<HolisticCameraProps> = ({ 
  enabled, config, facingMode, isMirrored, prediction, isAnalyzing, 
  onViewportStatusChange, onResults, onSequenceComplete, onFpsUpdate, onError
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [sessionState, setSessionState] = useState<SessionState>('IDLE');
  const sessionStateRef = useRef<SessionState>('IDLE');
  const sequenceBuffer = useRef<number[][]>([]);
  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);
  const cameraInstanceRef = useRef<any>(null);
  const holisticInstanceRef = useRef<any>(null);

  /**
   * alignSequenceLength: Ensures temporal consistency
   * Uses lastFrame padding to prevent ML "zero-shocks"
   */
  const alignSequenceLength = (sequence: number[][], targetLen: number): number[][] => {
    if (sequence.length === 0) return [];
    if (sequence.length >= targetLen) return sequence.slice(-targetLen);
    const padding = new Array(targetLen - sequence.length).fill(sequence[sequence.length - 1]);
    return [...sequence, ...padding];
  };

  const checkHandActivity = (results: any): boolean => {
    if (!results.poseLandmarks) return false;
    const lS = results.poseLandmarks[11], rS = results.poseLandmarks[12];
    if (!lS || !rS) return false;
    const threshold = Math.min(lS.y, rS.y) + 0.05;
    const activeLH = results.leftHandLandmarks && results.leftHandLandmarks.some((p: any) => p.y < threshold);
    const activeRH = results.rightHandLandmarks && results.rightHandLandmarks.some((p: any) => p.y < threshold);
    return !!(activeLH || activeRH);
  };

  const checkViewportLogic = (poseLandmarks: any[] | undefined): ViewportStatus => {
    if (!poseLandmarks || poseLandmarks.length === 0) return { state: 'NOT_DETECTED', instruction: 'Detecting User...' };
    const lS = poseLandmarks[11], rS = poseLandmarks[12];
    if (!lS || !rS) return { state: 'NOT_DETECTED', instruction: 'Show Full Shoulders' };
    const shoulderScale = Math.hypot(rS.x - lS.x, rS.y - lS.y);
    if (shoulderScale > 0.60) return { state: 'TOO_CLOSE', instruction: 'MOVE BACK' };
    if (shoulderScale < 0.08) return { state: 'TOO_FAR', instruction: 'MOVE CLOSER' };
    if (sessionStateRef.current === 'RECORDING') return { state: 'RECORDING', instruction: 'RECORDING...' };
    if (isAnalyzing) return { state: 'ANALYZING', instruction: 'ANALYZING...' };
    return { state: 'READY', instruction: 'READY TO SIGN' };
  };

  useEffect(() => {
    if (!enabled) {
        cameraInstanceRef.current?.stop();
        holisticInstanceRef.current?.close();
        return;
    }

    const active = { current: true };
    const MP_H = (HolisticModule as any).default || HolisticModule;
    const MP_D = (DrawingModule as any).default || DrawingModule;

    const holistic = new MP_H.Holistic({ 
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/holistic/${file}` 
    });
    holisticInstanceRef.current = holistic;
    holistic.setOptions({ modelComplexity: 1, smoothLandmarks: true, minDetectionConfidence: 0.5, minTrackingConfidence: 0.5 });

    holistic.onResults((results: any) => {
      if (!active.current || !enabled) return;
      const viewport = checkViewportLogic(results.poseLandmarks);
      onViewportStatusChange(viewport);

      const { data } = FeatureExtractor.extract(results);
      const handsActive = checkHandActivity(results);

      if (sessionStateRef.current === 'IDLE' && handsActive && viewport.state === 'READY') {
        sessionStateRef.current = 'RECORDING';
        setSessionState('RECORDING');
        sequenceBuffer.current = [data];
      } else if (sessionStateRef.current === 'RECORDING') {
        sequenceBuffer.current.push(data);
        if (sequenceBuffer.current.length > 120) sequenceBuffer.current.shift();

        if (!handsActive) {
          if (sequenceBuffer.current.length > 8) {
            sessionStateRef.current = 'ANALYZING';
            setSessionState('ANALYZING');
            // Ensure 64 frame window with consistency padding
            const aligned = alignSequenceLength(sequenceBuffer.current, 64);
            onSequenceComplete(aligned);
            setTimeout(() => { 
                sessionStateRef.current = 'IDLE'; 
                setSessionState('IDLE'); 
                sequenceBuffer.current = []; 
            }, config.inference_logic.prediction_cooldown_ms);
          } else {
            sessionStateRef.current = 'IDLE'; setSessionState('IDLE'); sequenceBuffer.current = [];
          }
        }
      }

      onResults(results, data);
      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current >= 1000) {
        onFpsUpdate(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0; lastTimeRef.current = now;
      }

      const canvasCtx = canvasRef.current?.getContext('2d');
      if (!canvasCtx || !canvasRef.current) return;
      canvasCtx.save();
      canvasCtx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      if (isMirrored) { canvasCtx.scale(-1, 1); canvasCtx.translate(-canvasRef.current.width, 0); }
      canvasCtx.drawImage(results.image, 0, 0, canvasRef.current.width, canvasRef.current.height);

      const drawSet = (pts: any[], conn: any, color: string) => {
        if (!pts) return;
        MP_D.drawConnectors(canvasCtx, pts, conn, { color, lineWidth: 1.5 });
        MP_D.drawLandmarks(canvasCtx, pts, { color, lineWidth: 1, radius: 2 });
      };

      drawSet(results.poseLandmarks, MP_H.POSE_CONNECTIONS, config.visual_config.colors.pose);
      drawSet(results.leftHandLandmarks, MP_H.HAND_CONNECTIONS, config.visual_config.colors.hands);
      drawSet(results.rightHandLandmarks, MP_H.HAND_CONNECTIONS, config.visual_config.colors.hands);
      if (results.faceLandmarks) {
          MP_D.drawConnectors(canvasCtx, results.faceLandmarks, MP_H.FACEMESH_TESSELATION, { color: config.visual_config.colors.face, lineWidth: 0.5 });
      }
      canvasCtx.restore();
      if (isLoading) setIsLoading(false);
    });

    const CameraClass = (CameraModule as any).default?.Camera || (CameraModule as any).Camera;
    cameraInstanceRef.current = new CameraClass(videoRef.current!, {
      onFrame: async () => { 
        if (videoRef.current && active.current && enabled) {
          try { await holistic.send({ image: videoRef.current }); } catch (e) {}
        }
      },
      width: 1280, height: 720, facingMode
    });

    cameraInstanceRef.current.start().catch((err: any) => {
      setIsLoading(false);
      onError(err.name || 'Camera Error');
    });

    return () => { active.current = false; cameraInstanceRef.current?.stop(); holistic.close(); };
  }, [enabled, facingMode]);

  return (
    <div className={`relative w-full h-full bg-black overflow-hidden ${sessionState === 'RECORDING' ? 'ring-4 ring-indigo-500 ring-inset animate-pulse' : ''}`}>
      {isLoading && enabled && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-950">
          <div className="w-10 h-10 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"/>
          <p className="text-indigo-400 font-bold uppercase tracking-[0.3em] text-[9px]">Waking ML Sensors...</p>
        </div>
      )}
      <video ref={videoRef} className="hidden" playsInline muted />
      <canvas ref={canvasRef} className={`w-full h-full object-cover ${!enabled ? 'hidden' : ''}`} width={1280} height={720} />
    </div>
  );
};

export default HolisticCamera;

import React, { useState, useEffect, useRef } from 'react';
import { Zap, RefreshCw, Upload, Play, Settings, X, Loader2, Video, Terminal, Activity, FileVideo, Trash2, RotateCcw, ChevronRight, BarChart3, AlertCircle } from 'lucide-react';
import HolisticCamera from './components/HolisticCamera';
import { signEngine } from './services/SignEngine';
import { videoProcessor } from './services/VideoProcessor';
import { LandmarkStats, AppConfig, ViewportStatus, PredictionResult } from './types';

type AppMode = 'LIVE' | 'UPLOAD';

interface ProcessLog {
  id: number;
  message: string;
  type: 'info' | 'success' | 'warning' | 'frame' | 'result' | 'debug';
}

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig | null>(null);
  const [appMode, setAppMode] = useState<AppMode>('LIVE');
  const [cameraError, setCameraError] = useState<string | null>(null);
  const [stats, setStats] = useState<LandmarkStats>({
    face: 0, pose: 0, leftHand: 0, rightHand: 0, total: 0, activeFeatures: 0
  });
  const [fps, setFps] = useState<number>(0);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('user');
  const [isMirrored, setIsMirrored] = useState(true);
  const [viewportStatus, setViewportStatus] = useState<ViewportStatus>({ state: 'NOT_DETECTED', instruction: 'Detecting...' });
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);
  const [topRankings, setTopRankings] = useState<{word: string, confidence: number}[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [engineStatus, setEngineStatus] = useState<string>('Initializing...');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [uploadProgress, setUploadProgress] = useState<number>(0);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [logs, setLogs] = useState<ProcessLog[]>([]);

  const lastStatsUpdate = useRef<number>(0);
  const logEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetch('./app_config.json')
      .then(r => r.json())
      .then(setConfig);

    const interval = setInterval(() => {
      setEngineStatus(signEngine.getEngineStatus());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  const addLog = (message: string, type: ProcessLog['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-1000), { id: Date.now() + Math.random(), message, type }]);
  };

  const handleSequence = async (sequence: number[][]) => {
    if (!config) return;
    setIsAnalyzing(true);
    try {
        const response = await signEngine.predict(sequence, config);
        if (response) {
            setPrediction(response.result);
            setTopRankings(response.debug.top10);
            if (appMode === 'LIVE') {
                setTimeout(() => setPrediction(null), 5000);
            }
        }
    } catch (e) {
        setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
        setIsAnalyzing(false);
    }
  };

  const handleResults = (res: any, filtered: number[]) => {
    const now = Date.now();
    if (now - lastStatsUpdate.current < 250) return;
    lastStatsUpdate.current = now;

    setStats({
      face: res.faceLandmarks?.length || 0,
      pose: res.poseLandmarks?.length || 0,
      leftHand: res.leftHandLandmarks?.length || 0,
      rightHand: res.rightHandLandmarks?.length || 0,
      total: (res.faceLandmarks?.length || 0) + (res.poseLandmarks?.length || 0) + (res.leftHandLandmarks?.length || 0) + (res.rightHandLandmarks?.length || 0),
      activeFeatures: filtered.length
    });
  };

  const onFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setUploadedFile(e.target.files[0]);
      setPrediction(null);
      setTopRankings([]);
      setLogs([]);
      addLog(`[SYSTEM] Linked source: ${e.target.files[0].name}`, 'success');
    }
  };

  const handleReset = () => {
    setUploadedFile(null);
    setPrediction(null);
    setTopRankings([]);
    setLogs([]);
    setUploadProgress(0);
    setCameraError(null);
  };

  const handleAnalyzeVideo = async () => {
    if (!uploadedFile || !config) return;

    setIsAnalyzing(true);
    setPrediction(null);
    setTopRankings([]);
    setLogs([]);
    addLog(">> BOOTING INFERENCE ENGINE", "info");

    try {
      const sequence = await videoProcessor.processVideo(
        uploadedFile, 
        config, 
        (p) => setUploadProgress(p),
        (frameIdx, meta) => {
          const handsDetected = !meta.handImputed;
          const logMsg = `F${frameIdx.toString().padStart(2, '0')} | P:${meta.pose} LH:${meta.lh} RH:${meta.rh} | CX:${meta.refX.toFixed(2)} SCALE:${meta.scale.toFixed(2)}`;
          addLog(logMsg, handsDetected ? 'frame' : 'warning');
        }
      );

      addLog(">> EXTRACTION COMPLETED (64 FRAMES)", "success");
      const response = await signEngine.predict(sequence, config);

      if (response) {
        const { result, debug } = response;
        setTopRankings(debug.top10);

        // DISPLAY ML INTEGRITY DATA
        addLog(`>> ML INTEGRITY: MIN:${debug.min.toFixed(3)} MAX:${debug.max.toFixed(3)} MEAN:${debug.mean.toFixed(3)}`, "debug");
        addLog(`>> TENSOR SHAPE: [${debug.inputShape.join(', ')}]`, "debug");

        addLog(">> PROBABILITY DISTRIBUTION:", "info");
        debug.top10.forEach((p, i) => {
            const isMatch = p.word === result?.word && result?.word !== 'NA';
            const bar = "█".repeat(Math.round(p.confidence * 15)).padEnd(15, '░');
            addLog(`${(i+1)}. ${p.word.padEnd(14)} [${bar}] ${(p.confidence * 100).toFixed(1)}%`, isMatch ? 'success' : 'info');
        });

        if (result?.word !== 'NA') {
          addLog(`>> FINAL PREDICTION: ${result?.word}`, "result");
        } else {
          addLog(">> UNCERTAIN PREDICTION (BELOW THRESHOLD)", "warning");
        }
        setPrediction(result);
      }
    } catch (err) {
      addLog(`>> FATAL ERROR: ${err instanceof Error ? err.message : 'Unknown exception'}`, 'warning');
      setPrediction({ word: 'ERROR', confidence: 0 });
    } finally {
      setIsAnalyzing(false);
      setUploadProgress(0);
    }
  };

  if (!config) return <div className="h-screen bg-slate-950 flex items-center justify-center text-indigo-400 font-black tracking-widest uppercase text-xs italic">SignSense Booting...</div>;

  const isNA = prediction?.word === 'NA' || prediction?.word === 'ERROR';

  return (
    <div className="flex flex-col h-screen w-screen bg-slate-950 text-slate-100 font-sans selection:bg-indigo-500/30 overflow-hidden">
      <header className="absolute top-4 inset-x-4 flex items-center justify-between z-50 pointer-events-none">
        <div className="flex items-center gap-2 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-1.5 pr-3 rounded-lg pointer-events-auto shadow-2xl">
          <div className="p-1 bg-indigo-600 rounded shadow-lg shadow-indigo-600/30"><Zap className="w-3.5 h-3.5 text-white" /></div>
          <h1 className="text-[9px] font-black uppercase tracking-[0.2em] text-white italic">{config.app_settings.app_name}</h1>
        </div>

        <div className="flex items-center gap-1.5 pointer-events-auto bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-1 rounded-xl shadow-xl">
            <button 
                onClick={() => { setAppMode('LIVE'); handleReset(); }}
                className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all flex items-center gap-2 ${appMode === 'LIVE' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Video className="w-3 h-3" /> Live
            </button>
            <button 
                onClick={() => { setAppMode('UPLOAD'); handleReset(); }}
                className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all flex items-center gap-2 ${appMode === 'UPLOAD' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}
            >
                <Upload className="w-3 h-3" /> Batch
            </button>
        </div>

        <div className="flex items-center gap-1.5 pointer-events-auto">
          {appMode === 'LIVE' && (
            <button onClick={() => setFacingMode(f => f === 'user' ? 'environment' : 'user')} className="p-2 bg-slate-900/90 border border-slate-800 rounded-lg shadow-xl hover:bg-slate-800 transition-colors"><RefreshCw className="w-3.5 h-3.5 text-indigo-400" /></button>
          )}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 lg:hidden bg-slate-900/90 border border-slate-800 rounded-lg hover:bg-slate-800 transition-colors"><Settings className="w-3.5 h-3.5 text-indigo-400" /></button>
        </div>
      </header>

      <main className="flex-1 relative flex overflow-hidden">
